import microcoapy as coap
import machine

# Initialize CoAP server
coap_server = coap.COAPServer()

# Define sensor value
temp = 25

# Define actuator value
light = 0

# Handle GET request for /sensors/temp
@coap_server.get('/sensors/temp')
def get_temp(request):
    return coap.Message(code=coap.COAP_CONTENT, payload=str(temp))

# Handle PUT request for /sensors/temp
@coap_server.put('/sensors/temp')
def set_temp(request):
    global temp
    temp = float(request.payload)
    return coap.Message(code=coap.COAP_CHANGED)

# Handle GET request for /actuators/light
@coap_server.get('/actuators/light')
def get_light(request):
    return coap.Message(code=coap.COAP_CONTENT, payload=str(light))

# Handle PUT request for /actuators/light
@coap_server.put('/actuators/light')
def set_light(request):
    global light
    light = int(request.payload)
    return coap.Message(code=coap.COAP_CHANGED)

# Run CoAP server
coap_server.run()